 1	import type { FC } from 'react';
 2	
 3	import { Label, LabelGroup } from '@patternfly/react-core';
 4	import { isEmpty } from '@utils/helpers';
 5	import { t } from '@utils/i18n';
 6	
 7	import './LabelsViewDetailsItemContent.scss';
 8	
 9	type LabelsViewDetailsItemContentProps = {
10	  labels: Record<string, string> | undefined;
11	};
12	
13	const LabelsViewDetailsItemContent: FC<LabelsViewDetailsItemContentProps> = ({ labels }) => {
14	  return (
15	    <LabelGroup
16	      className={`labels-view-details-item${isEmpty(labels) ? '--empty' : ''}`}
17	      numLabels={4}
18	    >
19	      {isEmpty(labels) ? (
20	        <span className="text-muted">{t('No labels defined')}</span>
21	      ) : (
22	        Object.keys(labels ?? {})?.map((key) => {
23	          const labelText = labels?.[key] ? `${key}=${labels[key]}` : key;
24	
25	          return (
26	            <Label className="co-label" key={key} textMaxWidth={'25em'}>
27	              {labelText}
28	            </Label>
29	          );
30	        })
31	      )}
32	    </LabelGroup>
33	  );
34	};
35	
36	export default LabelsViewDetailsItemContent;

